import{_ as e,o as s,c as a,ag as o}from"./chunks/framework.6MCaaFDc.js";const c=JSON.parse('{"title":"Multimedia","description":"","frontmatter":{},"headers":[],"relativePath":"theory/internet/multimedia.md","filePath":"theory/internet/multimedia.md"}'),i={name:"theory/internet/multimedia.md"};function r(d,t,n,l,m,h){return s(),a("div",null,[...t[0]||(t[0]=[o(`<h1 id="multimedia" tabindex="-1">Multimedia <a class="header-anchor" href="#multimedia" aria-label="Permalink to &quot;Multimedia&quot;">​</a></h1><p>A modern web page combines text, images, audio, video, and animations seamlessly. Behind every video that loads instantly and every photo that downloads in seconds is a compression algorithm carefully removing data that your eyes and ears won&#39;t miss.</p><div class="note custom-block github-alert"><p class="custom-block-title">Grade 11</p><p>Multimedia and compression are Grade 11 topics. Focus on lossless vs lossy compression, file formats, and streaming.</p></div><hr><h2 id="what-is-multimedia" tabindex="-1">What is Multimedia? <a class="header-anchor" href="#what-is-multimedia" aria-label="Permalink to &quot;What is Multimedia?&quot;">​</a></h2><p><strong>Multimedia</strong> is the combination of multiple types of media content — text, images, audio, video, and animation — delivered through a computer or device.</p><table tabindex="0"><thead><tr><th>Media Type</th><th>File Formats</th><th>Typical Use</th></tr></thead><tbody><tr><td>Text</td><td>.txt, .doc, .pdf</td><td>Documents, articles</td></tr><tr><td>Images</td><td>.jpg, .png, .gif, .svg, .webp</td><td>Photos, graphics, icons</td></tr><tr><td>Audio</td><td>.mp3, .wav, .flac, .aac</td><td>Music, podcasts, voice</td></tr><tr><td>Video</td><td>.mp4, .avi, .mkv, .webm</td><td>Films, tutorials, streaming</td></tr><tr><td>Animation</td><td>.gif, .webm, CSS animations</td><td>Web graphics, short loops</td></tr></tbody></table><hr><h2 id="compression" tabindex="-1">Compression <a class="header-anchor" href="#compression" aria-label="Permalink to &quot;Compression&quot;">​</a></h2><p><strong>Compression</strong> reduces file size by encoding data more efficiently. Smaller files are faster to upload, download, and stream, and take up less storage.</p><h3 id="lossless-vs-lossy-compression" tabindex="-1">Lossless vs Lossy Compression <a class="header-anchor" href="#lossless-vs-lossy-compression" aria-label="Permalink to &quot;Lossless vs Lossy Compression&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Feature</th><th><strong>Lossless</strong></th><th><strong>Lossy</strong></th></tr></thead><tbody><tr><td>How</td><td>Removes redundant data patterns; fully reversible</td><td>Permanently discards detail that humans barely notice</td></tr><tr><td>Quality</td><td>No quality loss — perfectly reconstructed</td><td>Reduced quality (often imperceptible at moderate compression)</td></tr><tr><td>File size reduction</td><td>Moderate</td><td>Much greater</td></tr><tr><td>Use case</td><td>Documents, medical images, archival</td><td>Photos, audio, video for web</td></tr><tr><td>Examples</td><td>PNG, GIF, ZIP, FLAC, BMP (raw)</td><td>JPEG, MP3, MP4, AAC, WebP</td></tr></tbody></table><div class="tip custom-block github-alert"><p class="custom-block-title">Choose the right type</p><p></p><ul><li>Compress a logo or screenshot → use <strong>PNG</strong> (lossless — sharp edges preserved)</li><li>Compress a photograph for web → use <strong>JPEG</strong> (lossy — small file, minimal visible loss)</li><li>Never use JPEG for screenshots with text — the compression artefacts make text blurry</li></ul></div><hr><h2 id="image-formats" tabindex="-1">Image Formats <a class="header-anchor" href="#image-formats" aria-label="Permalink to &quot;Image Formats&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Format</th><th>Type</th><th>Best For</th><th>Notes</th></tr></thead><tbody><tr><td><strong>JPEG / JPG</strong></td><td>Lossy</td><td>Photographs</td><td>Variable quality setting; no transparency</td></tr><tr><td><strong>PNG</strong></td><td>Lossless</td><td>Screenshots, logos, graphics</td><td>Supports transparency (alpha channel)</td></tr><tr><td><strong>GIF</strong></td><td>Lossless (limited)</td><td>Simple animations, icons</td><td>Only 256 colours; poor for photos</td></tr><tr><td><strong>SVG</strong></td><td>Vector</td><td>Icons, illustrations</td><td>Scalable to any size without quality loss</td></tr><tr><td><strong>WebP</strong></td><td>Both</td><td>Web images</td><td>Modern format; better compression than JPEG/PNG</td></tr><tr><td><strong>BMP</strong></td><td>Uncompressed</td><td>Raw image storage</td><td>Very large files</td></tr></tbody></table><h3 id="image-quality-and-file-size" tabindex="-1">Image Quality and File Size <a class="header-anchor" href="#image-quality-and-file-size" aria-label="Permalink to &quot;Image Quality and File Size&quot;">​</a></h3><ul><li><strong>Resolution</strong>: width × height in pixels (e.g. 1920 × 1080)</li><li><strong>Colour depth</strong>: bits per pixel — 24-bit = 16.7 million colours</li><li><strong>File size (uncompressed)</strong>: width × height × colour depth ÷ 8 bytes</li></ul><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Example: 1920 × 1080 × 24-bit = 1920 × 1080 × 3 bytes = ~6.2 MB uncompressed</span></span>
<span class="line"><span>After JPEG compression: ~300 KB–2 MB depending on quality setting</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><hr><h2 id="audio-formats-and-compression" tabindex="-1">Audio Formats and Compression <a class="header-anchor" href="#audio-formats-and-compression" aria-label="Permalink to &quot;Audio Formats and Compression&quot;">​</a></h2><h3 id="how-audio-compression-works" tabindex="-1">How audio compression works: <a class="header-anchor" href="#how-audio-compression-works" aria-label="Permalink to &quot;How audio compression works:&quot;">​</a></h3><ul><li><strong>Sampling</strong>: audio wave measured thousands of times per second</li><li><strong>Bit depth</strong>: number of bits per sample (16-bit = 65,536 amplitude levels)</li><li><strong>Sample rate</strong>: number of samples per second (44,100 Hz = CD quality)</li></ul><p><strong>Uncompressed audio size:</strong> sample rate × bit depth × channels × duration<br><code>44,100 Hz × 16-bit × 2 channels = 1,411,200 bits/second ≈ 176 KB/s</code></p><h3 id="audio-formats" tabindex="-1">Audio Formats <a class="header-anchor" href="#audio-formats" aria-label="Permalink to &quot;Audio Formats&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Format</th><th>Type</th><th>Quality</th><th>Use</th></tr></thead><tbody><tr><td><strong>WAV</strong></td><td>Uncompressed</td><td>Perfect</td><td>Recording, professional audio</td></tr><tr><td><strong>FLAC</strong></td><td>Lossless compressed</td><td>Perfect</td><td>Audiophile storage</td></tr><tr><td><strong>MP3</strong></td><td>Lossy</td><td>Very good at 128–320 kbps</td><td>Music streaming, downloads</td></tr><tr><td><strong>AAC</strong></td><td>Lossy</td><td>Better than MP3 at same size</td><td>Apple, streaming services</td></tr><tr><td><strong>OGG</strong></td><td>Lossy</td><td>Good</td><td>Open source streaming</td></tr></tbody></table><p><strong>MP3 compression removes:</strong></p><ul><li>Frequencies humans can barely hear</li><li>Sounds masked by louder simultaneous sounds</li><li>Result: file size ~90% smaller than WAV with similar perceived quality at 192+ kbps</li></ul><hr><h2 id="video-formats-and-compression" tabindex="-1">Video Formats and Compression <a class="header-anchor" href="#video-formats-and-compression" aria-label="Permalink to &quot;Video Formats and Compression&quot;">​</a></h2><p>Video = sequence of image frames + audio track<br> Uncompressed video is enormous — compression is essential.</p><p><strong>Video = Images × Frame Rate</strong> At 30 fps, a 1920×1080 video generates: 30 × 6.2 MB = ~186 MB per second uncompressed.</p><h3 id="video-codecs-compression-algorithms" tabindex="-1">Video Codecs (compression algorithms) <a class="header-anchor" href="#video-codecs-compression-algorithms" aria-label="Permalink to &quot;Video Codecs (compression algorithms)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Codec</th><th>Container</th><th>Type</th><th>Notes</th></tr></thead><tbody><tr><td><strong>H.264</strong></td><td>.mp4, .mkv</td><td>Lossy</td><td>Most widely supported</td></tr><tr><td><strong>H.265 (HEVC)</strong></td><td>.mp4, .mkv</td><td>Lossy</td><td>50% smaller than H.264 at same quality</td></tr><tr><td><strong>AV1</strong></td><td>.webm</td><td>Lossy</td><td>Open source; efficient; used by YouTube/Netflix</td></tr><tr><td><strong>VP9</strong></td><td>.webm</td><td>Lossy</td><td>Google&#39;s codec; used in YouTube</td></tr></tbody></table><p><strong>Container vs Codec:</strong></p><ul><li><strong>Codec</strong>: algorithm used to compress/decompress video</li><li><strong>Container (.mp4, .mkv)</strong>: file format that holds video + audio + metadata</li></ul><h3 id="frame-rate" tabindex="-1">Frame Rate <a class="header-anchor" href="#frame-rate" aria-label="Permalink to &quot;Frame Rate&quot;">​</a></h3><ul><li>24 fps — film</li><li>30 fps — standard TV</li><li>60 fps — gaming, sport</li><li>Higher fps = smoother motion but larger file</li></ul><hr><h2 id="streaming" tabindex="-1">Streaming <a class="header-anchor" href="#streaming" aria-label="Permalink to &quot;Streaming&quot;">​</a></h2><p><strong>Streaming</strong> delivers media continuously over the internet — playback begins before the file fully downloads.</p><h3 id="types" tabindex="-1">Types: <a class="header-anchor" href="#types" aria-label="Permalink to &quot;Types:&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Type</th><th>Description</th><th>Examples</th></tr></thead><tbody><tr><td><strong>On-demand streaming</strong></td><td>Watch/listen anytime</td><td>Netflix, YouTube, Spotify</td></tr><tr><td><strong>Live streaming</strong></td><td>Real-time broadcast</td><td>Twitch, live sports, news</td></tr></tbody></table><h3 id="adaptive-bitrate-streaming-abr" tabindex="-1">Adaptive Bitrate Streaming (ABR): <a class="header-anchor" href="#adaptive-bitrate-streaming-abr" aria-label="Permalink to &quot;Adaptive Bitrate Streaming (ABR):&quot;">​</a></h3><ul><li>Service continuously monitors your connection speed</li><li>Automatically switches video quality (e.g. 4K → 1080p → 720p) if bandwidth drops</li><li>Minimises buffering — keeps playback smooth</li></ul><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Good connection:  4K (15–25 Mbps)</span></span>
<span class="line"><span>Average connection:  1080p (5–8 Mbps)</span></span>
<span class="line"><span>Poor connection:  480p (1.5–3 Mbps)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h3 id="buffering" tabindex="-1">Buffering: <a class="header-anchor" href="#buffering" aria-label="Permalink to &quot;Buffering:&quot;">​</a></h3><ul><li>Video is downloaded slightly ahead of playback</li><li>If download speed drops below playback rate → buffer empties → buffering pause</li></ul><hr><h2 id="digital-rights-management-drm" tabindex="-1">Digital Rights Management (DRM) <a class="header-anchor" href="#digital-rights-management-drm" aria-label="Permalink to &quot;Digital Rights Management (DRM)&quot;">​</a></h2><p><strong>DRM</strong> is technology used to control how digital content is used, copied, and distributed.</p><ul><li>Prevents unauthorised copying and sharing</li><li>Streaming services encrypt content — only licenced apps can decrypt</li><li>Examples: Netflix, Spotify, Kindle</li><li>Criticism: prevents legitimate personal use (e.g. moving content between devices)</li></ul><hr><h2 id="multimedia-on-websites" tabindex="-1">Multimedia on Websites <a class="header-anchor" href="#multimedia-on-websites" aria-label="Permalink to &quot;Multimedia on Websites&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Element</th><th>Consideration</th></tr></thead><tbody><tr><td>Images</td><td>Compress before uploading; use WebP for best compression</td></tr><tr><td>Video</td><td>Embed from YouTube/Vimeo to avoid hosting bandwidth costs</td></tr><tr><td>Audio</td><td>Use compressed MP3/AAC; not WAV</td></tr><tr><td>Animation</td><td>Prefer CSS animations or SVG over heavy GIFs</td></tr><tr><td>Accessibility</td><td>Add alt text to images; captions to videos</td></tr><tr><td>Performance</td><td>Large uncompressed media slows page load → poor SEO</td></tr></tbody></table><hr><h2 id="key-terms" tabindex="-1">Key Terms <a class="header-anchor" href="#key-terms" aria-label="Permalink to &quot;Key Terms&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Term</th><th>Definition</th></tr></thead><tbody><tr><td><strong>Multimedia</strong></td><td>Combination of text, images, audio, video, animation</td></tr><tr><td><strong>Compression</strong></td><td>Reducing file size by encoding data more efficiently</td></tr><tr><td><strong>Lossless</strong></td><td>Compression that allows perfect reconstruction — no quality loss</td></tr><tr><td><strong>Lossy</strong></td><td>Compression that permanently discards data — smaller files</td></tr><tr><td><strong>Codec</strong></td><td>Algorithm for compressing/decompressing audio or video</td></tr><tr><td><strong>Container</strong></td><td>File format holding compressed video, audio, and metadata</td></tr><tr><td><strong>Streaming</strong></td><td>Delivering media in real-time over the internet</td></tr><tr><td><strong>Adaptive bitrate</strong></td><td>Streaming that adjusts quality based on available bandwidth</td></tr><tr><td><strong>Buffering</strong></td><td>Pre-loading media ahead of playback</td></tr><tr><td><strong>DRM</strong></td><td>Technology controlling how digital content is used/copied</td></tr><tr><td><strong>Sample rate</strong></td><td>Number of audio measurements per second (e.g. 44,100 Hz)</td></tr></tbody></table><hr><h2 id="exam-focus" tabindex="-1">Exam Focus <a class="header-anchor" href="#exam-focus" aria-label="Permalink to &quot;Exam Focus&quot;">​</a></h2><div class="important custom-block github-alert"><p class="custom-block-title">High-Frequency Questions</p><p></p><ol><li><p><strong>&quot;What is the difference between lossless and lossy compression? Give an example of each.&quot;</strong> — Lossless: no quality loss, fully reversible (PNG, FLAC, ZIP); Lossy: permanently removes detail (JPEG, MP3, MP4)</p></li><li><p><strong>&quot;Give a reason why JPEG is preferred over PNG for photographs on a website&quot;</strong> — JPEG produces much smaller file sizes using lossy compression; for photographs the quality loss is barely noticeable, resulting in faster page loads</p></li><li><p><strong>&quot;What is streaming? How is it different from downloading?&quot;</strong> — Streaming delivers media continuously — playback starts immediately; downloading saves the complete file first before playback</p></li><li><p><strong>&quot;What is adaptive bitrate streaming?&quot;</strong> — Automatically adjusts video quality based on the user&#39;s connection speed to minimise buffering and provide the best experience</p></li><li><p><strong>&quot;Why is video compression necessary?&quot;</strong> — Uncompressed video is enormous (hundreds of MB per second); compression reduces file sizes making storage, transfer, and streaming practical</p></li></ol></div>`,61)])])}const u=e(i,[["render",r]]);export{c as __pageData,u as default};
